def generate_cop_health_report(
    quarter: str,
    total_members: int,
    health_metrics: dict,
) -> str:
    """Generate a quarterly CoP health report for the executive sponsor."""
    prompt = f"""Write a quarterly health report for a Claude Community of Practice.

Quarter: {quarter}
Total members: {total_members}
Metrics:
- Contributing members: {health_metrics.get("contributing_pct", 0)}% of total
- Showcase attendance rate: {health_metrics.get("attendance_pct", 0)}%
- Prompt library monthly views: {health_metrics.get("library_views", 0)}
- Use cases surfaced to governance: {health_metrics.get("use_cases_surfaced", 0)}
- Member satisfaction NPS: {health_metrics.get("member_nps", 0)}
- Net new members this quarter: {health_metrics.get("new_members", 0)}

Write a 3-paragraph report:
1. Overall health assessment (one of: Thriving / Healthy / Needs attention / At risk)
2. Two highlights from the quarter
3. One recommended action for next quarter with a named owner"""

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content": prompt}],
    )
    return resp.content[0].text


health_report = generate_cop_health_report(
    quarter="Q1 2025",
    total_members=87,
    health_metrics={
        "contributing_pct": 44,
        "attendance_pct": 52,
        "library_views": 312,
        "use_cases_surfaced": 5,
        "member_nps": 38,
        "new_members": 22,
    },
)
print(health_report)
